'use client';

import React from 'react';
import { motion } from 'framer-motion';
import { 
  Phone, Mail, MapPin, MessageCircle, 
  Clock, Send, ArrowRight 
} from 'lucide-react';

// Animation
const fadeInUp = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.6 } }
};

export default function ContactPage() {
  return (
    <main className="bg-gray-50 min-h-screen font-sans pb-24">
      
      {/* --- HERO HEADER (Dark & Premium) --- */}
      <section className="relative bg-slate-900 text-white pt-28 pb-20 px-6 rounded-b-[3rem] shadow-2xl overflow-hidden">
        {/* Background Decoration */}
        <div className="absolute top-0 left-0 w-full h-full overflow-hidden z-0">
           <div className="absolute top-[-10%] left-[-5%] w-96 h-96 bg-green-600/20 rounded-full blur-[80px]"></div>
           <div className="absolute bottom-[-10%] right-[-5%] w-72 h-72 bg-blue-600/20 rounded-full blur-[80px]"></div>
        </div>

        <div className="relative z-10 max-w-4xl mx-auto text-center">
          <motion.div initial="hidden" animate="visible" variants={fadeInUp}>
            <div className="inline-flex items-center justify-center p-3 bg-white/10 backdrop-blur-md rounded-2xl mb-6 border border-white/10 shadow-lg">
              <MessageCircle size={32} className="text-green-400" />
            </div>
            
            <h1 className="text-4xl md:text-6xl font-black mb-6 tracking-tight">
              Get in Touch with <br/> <span className="text-green-400">CGINFRAX</span>
            </h1>
            <p className="text-slate-300 text-lg md:text-xl max-w-2xl mx-auto leading-relaxed">
              Have a query about a property or construction? We are just one click away. No bots, real people.
            </p>
          </motion.div>
        </div>
      </section>

      {/* --- CONTACT CARDS --- */}
      <div className="max-w-6xl mx-auto px-6 -mt-12 relative z-20">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          
          {/* 1. WhatsApp Card (Priority) */}
          <ContactCard 
            icon={<MessageCircle size={32} />}
            title="Chat on WhatsApp"
            detail="+91 91314 60470"
            subDetail="Fastest response (Within 10 mins)"
            action={() => window.open('https://wa.me/919131460470', '_blank')}
            btnText="Chat Now"
            color="green"
            highlight={true}
          />

          {/* 2. Phone Call */}
          <ContactCard 
            icon={<Phone size={32} />}
            title="Call Us Directly"
            detail="+91 91314 60470"
            subDetail="Mon-Sat, 9:00 AM to 7:00 PM"
            action={() => window.open('tel:919131460470')}
            btnText="Call Now"
            color="blue"
          />

          {/* 3. Email */}
          <ContactCard 
            icon={<Mail size={32} />}
            title="Email Support"
            detail="support@cginfrax.com"
            subDetail="For corporate & legal queries"
            action={() => window.open('mailto:support@cginfrax.com')}
            btnText="Send Email"
            color="purple"
          />

        </div>
      </div>

      {/* --- MESSAGE FORM SECTION --- */}
      <section className="max-w-4xl mx-auto px-6 mt-20">
        <div className="bg-white rounded-3xl shadow-xl border border-gray-100 p-8 md:p-12">
          
          <div className="text-center mb-10">
            <h2 className="text-3xl font-black text-slate-900 mb-4">Send a Message</h2>
            <p className="text-gray-500">Prefer writing? Fill the form below and our team will call you back.</p>
          </div>

          <form className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700 ml-1">Your Name</label>
                <input type="text" placeholder="Enter full name" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-4 outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-100 transition-all font-medium" />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700 ml-1">Mobile Number</label>
                <input type="tel" placeholder="+91 xxxxx xxxxx" className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-4 outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-100 transition-all font-medium" />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-bold text-slate-700 ml-1">Requirement</label>
              <select className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-4 outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-100 transition-all font-medium text-gray-600">
                <option>I want to Buy a Property</option>
                <option>I need Construction Services</option>
                <option>Hourly Stay Booking</option>
                <option>General Inquiry</option>
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-bold text-slate-700 ml-1">Message</label>
              <textarea rows="4" placeholder="Tell us more about your requirement..." className="w-full bg-gray-50 border border-gray-200 rounded-xl px-4 py-4 outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-100 transition-all font-medium resize-none"></textarea>
            </div>

            <button type="button" className="w-full bg-slate-900 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-black transition-transform active:scale-95 flex items-center justify-center gap-2 text-lg">
              Send Message <Send size={20} />
            </button>
          </form>

        </div>
      </section>

      {/* --- OFFICE LOCATION (Placeholder) --- */}
      <div className="max-w-4xl mx-auto px-6 mt-16 text-center">
        <div className="inline-flex items-center gap-2 bg-white px-6 py-3 rounded-full shadow-sm border border-gray-200 text-gray-600 font-medium">
          <MapPin size={20} className="text-red-500" />
          <span>Serving all major cities in <strong>Chhattisgarh</strong> (Bilaspur, Raipur, Durg)</span>
        </div>
      </div>

    </main>
  );
}

// --- Helper Component for Contact Cards ---
function ContactCard({ icon, title, detail, subDetail, action, btnText, color, highlight }) {
  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className={`bg-white p-8 rounded-3xl shadow-xl border-2 flex flex-col items-center text-center transition-transform hover:-translate-y-1 ${highlight ? 'border-green-500 ring-4 ring-green-50' : 'border-white'}`}
    >
      <div className={`w-16 h-16 rounded-2xl flex items-center justify-center mb-6 bg-${color}-50 text-${color}-600`}>
        {icon}
      </div>
      
      <h3 className="text-xl font-bold text-slate-900 mb-2">{title}</h3>
      <p className="text-lg font-black text-slate-800 mb-1">{detail}</p>
      <p className="text-sm text-gray-500 font-medium mb-6">{subDetail}</p>
      
      <button 
        onClick={action}
        className={`w-full py-3 rounded-xl font-bold flex items-center justify-center gap-2 transition-colors ${highlight ? 'bg-green-600 text-white hover:bg-green-700' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
      >
        {btnText} <ArrowRight size={16} />
      </button>
    </motion.div>
  );
}